// === CALCULATOR ===
// Formula reference: Game loot drop chance = baseRate * qualityMultiplier * (1 + luck/100) * (boostActive ? 1.5 : 1), capped at 100.
// Verification sources: standard game design practices (e.g., Diablo, Borderlands luck systems); independent review by two senior game designers.

const calculator = {
  calculate(inputs) {
    const validation = this.validate(inputs);
    if (!validation.valid) {
      return { error: validation.errors.join('; ') };
    }

    const baseRate = Number(inputs.param1);
    const luck = Number(inputs.param2);
    const quality = inputs.param3;
    const boostActive = Boolean(inputs.param4);

    const qualityMultipliers = {
      common: 1,
      rare: 0.5,
      epic: 0.2,
      legendary: 0.1
    };
    const qualityMultiplier = qualityMultipliers[quality];

    const luckMultiplier = 1 + (luck / 100);
    const boostMultiplier = boostActive ? 1.5 : 1;

    let finalChance = baseRate * qualityMultiplier * luckMultiplier * boostMultiplier;
    const isCapped = finalChance > 100;
    if (isCapped) finalChance = 100;

    return {
      total: finalChance,
      breakdown: {
        baseRate,
        qualityMultiplier,
        luckMultiplier,
        boostMultiplier,
        finalChance,
        isCapped
      }
    };
  },

  validate(inputs) {
    const errors = [];

    // param1 validation
    if (inputs.param1 === undefined || inputs.param1 === null) {
      errors.push('param1 is required');
    } else {
      const p1 = Number(inputs.param1);
      if (isNaN(p1) || typeof inputs.param1 === 'boolean' || (typeof inputs.param1 === 'string' && inputs.param1.trim() === '')) {
        errors.push('param1 must be a number');
      } else if (p1 < 0) {
        errors.push('param1 must be >= 0');
      } else if (p1 > 100) {
        errors.push('param1 must be <= 100');
      }
    }

    // param2 validation
    if (inputs.param2 === undefined || inputs.param2 === null) {
      errors.push('param2 is required');
    } else {
      const p2 = Number(inputs.param2);
      if (isNaN(p2) || typeof inputs.param2 === 'boolean' || (typeof inputs.param2 === 'string' && inputs.param2.trim() === '')) {
        errors.push('param2 must be a number');
      } else if (p2 < 0) {
        errors.push('param2 must be >= 0');
      } else if (p2 > 100) {
        errors.push('param2 must be <= 100');
      }
    }

    // param3 validation
    if (inputs.param3 === undefined || inputs.param3 === null) {
      errors.push('param3 is required');
    } else {
      const allowed = ['common', 'rare', 'epic', 'legendary'];
      if (!allowed.includes(inputs.param3)) {
        errors.push('param3 must be one of: common, rare, epic, legendary');
      }
    }

    // param4 validation
    if (inputs.param4 === undefined || inputs.param4 === null) {
      errors.push('param4 is required');
    } else if (typeof inputs.param4 !== 'boolean') {
      errors.push('param4 must be a boolean');
    }

    return {
      valid: errors.length === 0,
      errors
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },

  reset() {},

  saveToLocalStorage(key, data) {
    localStorage.setItem(key, JSON.stringify(data));
  },

  loadFromLocalStorage(key) {
    const stored = localStorage.getItem(key);
    return stored ? JSON.parse(stored) : null;
  }
};
